// GENERATED BY NAPL from prompts.napl — edit the prompt, not this file

use schemas_attribution::AttributionEntry;
use schemas_frontmatter::Frontmatter;
use targets::TargetAdapter;

/// Returns the last `count` characters (Unicode scalar values) of `text`; if
/// `text` has `count` or fewer characters, returns the whole `text`.
pub fn last_chars(text: &str, count: usize) -> String {
    let total = text.chars().count();
    if total <= count {
        return text.to_string();
    }
    text.chars().skip(total - count).collect()
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DepSummary {
    pub module: String,
    pub summary: String,
}

#[derive(Debug, Clone)]
pub struct IncrementalTaskInput {
    pub module: String,
    pub diff: String,
    pub intersecting_entries: Vec<AttributionEntry>,
    pub owned_files: Vec<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ReconcileFile {
    pub file: String,
    pub diff: String,
}

fn failure_block(failure: &str) -> Vec<String> {
    vec![
        String::new(),
        "A previous attempt FAILED its tests. Read the current files, fix the code and/or tests,"
            .to_string(),
        "and make the suite pass. Test output from the failed attempt:".to_string(),
        "```".to_string(),
        last_chars(failure.trim(), 6000),
        "```".to_string(),
    ]
}

pub fn build_agent_task(
    adapter: &TargetAdapter,
    frontmatter: &Frontmatter,
    body: &str,
    deps: &[DepSummary],
    failure: Option<&str>,
) -> String {
    let mut lines: Vec<String> = Vec::new();

    lines.push(format!(
        "You are a coding agent implementing the module \"{}\" as real, runnable",
        frontmatter.module
    ));
    lines.push(
        "source code in the current working directory. Write and edit files directly; scaffold the"
            .to_string(),
    );
    lines.push(
        "project and install dependencies as needed. The prompt below is the durable source of truth."
            .to_string(),
    );
    lines.push(String::new());
    lines.push("Target idiom guidance:".to_string());
    lines.push(adapter.idiom_guidance.clone());
    lines.push(String::new());
    lines.push(format!("Module: {}", frontmatter.module));

    if !frontmatter.deps.is_empty() {
        lines.push(format!(
            "Declared dependencies: {}",
            frontmatter.deps.join(", ")
        ));
    }

    if !deps.is_empty() {
        lines.push(String::new());
        lines.push("Other modules in this project (for context, do not reimplement them):".to_string());
        for dep in deps {
            lines.push(format!("- {}: {}", dep.module, dep.summary));
        }
    }

    lines.push(String::new());
    lines.push("Specification to implement (implement exactly this behavior):".to_string());
    lines.push("\"\"\"".to_string());
    lines.push(body.trim().to_string());
    lines.push("\"\"\"".to_string());
    lines.push(String::new());
    lines.push("Requirements:".to_string());
    lines.push(format!(
        "- Ensure \"{}\" passes from this directory before you finish.",
        adapter.test_command_label
    ));
    lines.push("- Write a real test suite covering the described behavior.".to_string());
    lines.push("- Use only functions/hooks, named exports, and no dead code.".to_string());
    lines.push(
        "- Do not edit files under node_modules; use the package manager for dependencies."
            .to_string(),
    );

    if let Some(f) = failure {
        lines.extend(failure_block(f));
    }

    lines.join("\n")
}

pub fn build_incremental_task(
    adapter: &TargetAdapter,
    frontmatter: &Frontmatter,
    body: &str,
    input: &IncrementalTaskInput,
    failure: Option<&str>,
) -> String {
    let mut lines: Vec<String> = Vec::new();

    lines.push(format!(
        "You are a coding agent making an INCREMENTAL update to the existing module \"{}\"",
        frontmatter.module
    ));
    lines.push(
        "in the current working directory. Its source code already exists and passes tests. The prompt"
            .to_string(),
    );
    lines.push(
        "(the durable source of truth) has CHANGED. Make the MINIMAL code edits needed to realize the"
            .to_string(),
    );
    lines.push(
        "prompt change — do not restructure or rewrite untouched code, do not reformat unrelated files."
            .to_string(),
    );
    lines.push(String::new());
    lines.push("Target idiom guidance:".to_string());
    lines.push(adapter.idiom_guidance.clone());
    lines.push(String::new());
    lines.push("Unified diff of the prompt change (old vs new prompt body):".to_string());
    lines.push("```diff".to_string());
    lines.push(input.diff.trim().to_string());
    lines.push("```".to_string());

    if !input.intersecting_entries.is_empty() {
        lines.push(String::new());
        lines.push(
            "The changed prompt lines are currently implemented by these owned code regions."
                .to_string(),
        );
        lines.push("Prefer editing exactly these regions:".to_string());
        for entry in &input.intersecting_entries {
            let note = if entry.note.is_empty() {
                String::new()
            } else {
                format!(" — {}", entry.note)
            };
            lines.push(format!(
                "- {} lines {}-{}{}",
                entry.file, entry.lines.start, entry.lines.end, note
            ));
        }
    }

    if !input.owned_files.is_empty() {
        lines.push(String::new());
        lines.push("Files owned by this module (edit only what the change requires):".to_string());
        for file in &input.owned_files {
            lines.push(format!("- {file}"));
        }
    }

    lines.push(String::new());
    lines.push("Full current prompt body (the target behavior after the change):".to_string());
    lines.push("\"\"\"".to_string());
    lines.push(body.trim().to_string());
    lines.push("\"\"\"".to_string());
    lines.push(String::new());
    lines.push("Requirements:".to_string());
    lines.push(format!(
        "- Ensure \"{}\" passes from this directory before you finish.",
        adapter.test_command_label
    ));
    lines.push(
        "- Update the existing tests to match the new behavior; do not delete unrelated tests."
            .to_string(),
    );
    lines.push("- Use only functions/hooks, named exports, and no dead code.".to_string());
    lines.push(
        "- Do not edit files under node_modules; use the package manager for dependencies."
            .to_string(),
    );

    if let Some(f) = failure {
        lines.extend(failure_block(f));
    }

    lines.join("\n")
}

pub fn build_reconcile_task(
    module: &str,
    prompt_file: &str,
    body: &str,
    files: &[ReconcileFile],
) -> String {
    let mut lines: Vec<String> = Vec::new();

    lines.push(format!(
        "You are reconciling hand edits back into the prompt (the durable source of truth) for the module \"{module}\"."
    ));
    lines.push(
        "A developer edited generated source files directly, so they no longer match the prompt."
            .to_string(),
    );
    lines.push(
        "Amend the prompt file below so that regenerating from it would reproduce the edited behavior."
            .to_string(),
    );
    lines.push(
        "Edit ONLY the prompt file(s) named here — NEVER touch the generated source under .napl/src."
            .to_string(),
    );
    lines.push(String::new());
    lines.push(format!("Prompt file to amend: {prompt_file}"));
    lines.push(String::new());
    lines.push("Current prompt body:".to_string());
    lines.push("\"\"\"".to_string());
    lines.push(body.trim().to_string());
    lines.push("\"\"\"".to_string());
    lines.push(String::new());
    lines.push("Observed source edits (recorded baseline -> current), per file:".to_string());

    for file in files {
        lines.push(format!("=== FILE: {} ===", file.file));
        lines.push("```diff".to_string());
        lines.push(file.diff.trim().to_string());
        lines.push("```".to_string());
    }

    lines.push(String::new());
    lines.push("Requirements:".to_string());
    lines.push(
        "- Rewrite or extend the prompt prose so its described behavior matches the edited source."
            .to_string(),
    );
    lines.push(
        "- Keep the YAML frontmatter valid; change only what the behavior change requires."
            .to_string(),
    );
    lines.push(
        "- Do not restate the diff verbatim — describe the intended behavior in the prompt's own voice."
            .to_string(),
    );
    lines.push(
        "- Do not edit, create, or delete any file under .napl/src — those are regenerated from the prompt."
            .to_string(),
    );

    lines.join("\n")
}

pub fn build_change_required_retry(base_task: &str) -> String {
    let lines = vec![
        base_task.to_string(),
        String::new(),
        "CRITICAL: A previous attempt made NO source changes at all, yet the prompt REQUIRES a change."
            .to_string(),
        "Either implement the change now with real edits to the source files, or — only if you are certain"
            .to_string(),
        "no code change is needed — state CLEARLY in your final message WHY no change is required (for"
            .to_string(),
        "example: the requirement is already satisfied by the existing code, or the instruction cannot be"
            .to_string(),
        "acted on because it is unclear or nonsensical). Do not finish silently without doing one of these."
            .to_string(),
    ];
    lines.join("\n")
}

pub fn build_ir_derivation_user(module: &str, body: &str, files: &str) -> String {
    let lines = vec![
        format!("Module name: {module}"),
        String::new(),
        "Prompt (the contract, in prose):".to_string(),
        "\"\"\"".to_string(),
        body.trim().to_string(),
        "\"\"\"".to_string(),
        String::new(),
        "Implementing source files:".to_string(),
        files.to_string(),
    ];
    lines.join("\n")
}

pub fn build_attribution_user(module: &str, numbered_body: &str, files: &str) -> String {
    let lines = vec![
        format!("Module: {module}"),
        String::new(),
        "Prompt body (1-based line numbers):".to_string(),
        numbered_body.to_string(),
        String::new(),
        "Implementing source files (1-based line numbers):".to_string(),
        files.to_string(),
    ];
    lines.join("\n")
}

pub fn build_attribution_repair(previous_output: &str, error_message: &str) -> String {
    let previous: String = previous_output
        .trim()
        .chars()
        .take(4000)
        .collect::<String>()
        .trim()
        .to_string();

    let lines = vec![
        String::new(),
        "Your PREVIOUS response was REJECTED as invalid and MUST be corrected. Return ONLY a single"
            .to_string(),
        "fenced ```yaml code block containing the list — no prose, no commentary, nothing else. Every"
            .to_string(),
        "item must reference a \"file\" that appears EXACTLY as labelled above, and the list must not be"
            .to_string(),
        "empty. Emit STRICTLY valid YAML with double-quoted string values.".to_string(),
        String::new(),
        "Your previous invalid response was:".to_string(),
        "\"\"\"".to_string(),
        previous,
        "\"\"\"".to_string(),
        String::new(),
        "The validation error was:".to_string(),
        error_message.to_string(),
    ];
    lines.join("\n")
}

pub fn build_ml_derivation_user(
    module: &str,
    numbered_body: &str,
    change_summary: &str,
    agent_output: &str,
) -> String {
    let output = last_chars(agent_output.trim(), 4000);
    let final_message = if output.is_empty() {
        "(no output captured)".to_string()
    } else {
        output
    };

    let lines = vec![
        format!("Module: {module}"),
        String::new(),
        "Prompt body (1-based line numbers) — the durable source of truth:".to_string(),
        numbered_body.to_string(),
        String::new(),
        "What the coding agent changed in the source (1-based line numbers), or \"NO CHANGES\":"
            .to_string(),
        change_summary.to_string(),
        String::new(),
        "The coding agent's final message:".to_string(),
        "\"\"\"".to_string(),
        final_message,
        "\"\"\"".to_string(),
    ];
    lines.join("\n")
}

pub const IR_DERIVATION_SYSTEM: &str = "You derive a CONTRACT-LEVEL intermediate representation (IR) from finished source code.\nYou are given a prompt (the contract in prose) and the source files that implement it.\nProduce a YAML document capturing CONTRACTS, not implementation, with these keys:\n- module: the exact module name provided.\n- deps: list of dependency module names (may be empty).\n- types: exported/public types as structural, language-neutral entries, each with a\n  \"name\" and a \"description\".\n- functions: the public functions/components, each with a \"name\", a language-neutral\n  \"signature\" string, and a \"behavior\" string covering pre/postconditions.\n- tests: the behavioral test cases as data, each with \"name\", \"given\", \"expect\".\nDo NOT include control flow, concurrency, memory idioms, or syntax trees.\nOutput ONLY a single fenced ```yaml code block and nothing else.";

pub const ATTRIBUTION_SYSTEM: &str = "You map lines of a prompt (the contract, in prose) to the exact lines of generated source\ncode that implement them. You are given the prompt body with 1-based line numbers, and each\nimplementing source file with 1-based line numbers.\n\nProduce a YAML list. Each item is a mapping with these keys:\n- promptLines: [start, end]  — 1-based inclusive line range in the prompt body.\n- file: the source file path exactly as labelled (relative to the target src directory).\n- lines: [start, end]  — 1-based inclusive line range in that file.\n- note: a short phrase describing what this code does (e.g. \"trims whitespace\").\n\nA prompt line may map to multiple code ranges, and one code range may map to multiple\nprompt lines — emit one item per concrete mapping. Only map lines that carry real intent;\nskip blank lines, headings, and boilerplate. Keep ranges tight.\nOutput ONLY a single fenced ```yaml code block containing the list, and nothing else.";

pub const ML_DERIVATION_SYSTEM: &str = "You are the MACHINE LAYER of a prompt compiler. A prompt (the contract, in prose) was compiled\nto source code by a coding agent. Your job is to record — for the human who wrote the prompt —\nwhere the prompt was ambiguous, what you had to assume, and anything else worth surfacing about\nthis compile.\n\nYou are given: the numbered prompt body, the numbered changes the agent made to the source\n(or the literal text \"NO CHANGES\"), and the coding agent's final message.\n\nOutput a YAML list (which may be empty). Each item has these keys:\n- promptLines: [start, end]  — 1-based inclusive line range in the PROMPT BODY the entry is about.\n- kind: one of \"ambiguity\", \"assumption\", \"note\", or \"no-op\".\n- message: a one-line human-facing summary.\n- reasoning: a fuller explanation of what was unclear and what was done instead.\n- suggestion: OPTIONAL — a proposed clearer rewording of the prompt line(s).\n\nHow to choose kind:\n- \"ambiguity\": the prompt line is vague, contradictory, self-referential, out of place, or reads\n  like an accidental or nonsensical insertion — an odd literal string, a phrase that does not fit\n  the surrounding requirement, or wording a careful engineer would stop and question. BE AGGRESSIVE\n  about flagging strange, surprising, or unmotivated phrasing; do NOT smooth it over or assume the\n  author must have meant something reasonable.\n- \"assumption\": you had to decide something the prompt left open; record the choice you made.\n- \"note\": something worth surfacing that is neither an ambiguity nor an assumption.\n- \"no-op\": use ONLY when the changes are \"NO CHANGES\". Explain why nothing was produced — the\n  requirement was already satisfied by existing code, or the instruction could not be understood or\n  acted upon. When the changes are \"NO CHANGES\" you MUST emit at least one \"no-op\" entry.\n\nAn empty list is valid ONLY when the prompt is entirely clear AND real changes were made.\nOutput ONLY a single fenced ```yaml code block containing the list, and nothing else.";

pub const YAML_STRICTNESS: &str = "\n\nEmit STRICTLY valid YAML. Quote every string value with double quotes and escape any inner double quotes, especially values containing a colon, quote, or bracket.";

#[cfg(test)]
mod tests {
    use super::*;
    use schemas_line_range::LineRange;

    fn frontmatter(module: &str, deps: Vec<&str>) -> Frontmatter {
        Frontmatter {
            module: module.to_string(),
            deps: deps.into_iter().map(|s| s.to_string()).collect(),
            targets: Vec::new(),
            tests: Vec::new(),
            crate_name: None,
        }
    }

    fn adapter() -> TargetAdapter {
        targets::get_adapter("rust").unwrap()
    }

    #[test]
    fn last_chars_returns_whole_text_when_shorter_than_count() {
        assert_eq!(last_chars("hello", 10), "hello");
        assert_eq!(last_chars("hello", 5), "hello");
    }

    #[test]
    fn last_chars_returns_suffix_by_character_not_byte() {
        assert_eq!(last_chars("héllo world", 5), "world");
        let unicode = "日本語のテキスト";
        let truncated = last_chars(unicode, 3);
        assert_eq!(truncated, "キスト");
    }

    #[test]
    fn build_agent_task_minimal_shape() {
        let fm = frontmatter("auth/session", Vec::new());
        let a = adapter();
        let task = build_agent_task(&a, &fm, "Do the thing.\n", &[], None);

        let expected = [
            "You are a coding agent implementing the module \"auth/session\" as real, runnable",
            "source code in the current working directory. Write and edit files directly; scaffold the",
            "project and install dependencies as needed. The prompt below is the durable source of truth.",
            "",
            "Target idiom guidance:",
            &a.idiom_guidance,
            "",
            "Module: auth/session",
            "",
            "Specification to implement (implement exactly this behavior):",
            "\"\"\"",
            "Do the thing.",
            "\"\"\"",
            "",
            "Requirements:",
            "- Ensure \"cargo test\" passes from this directory before you finish.",
            "- Write a real test suite covering the described behavior.",
            "- Use only functions/hooks, named exports, and no dead code.",
            "- Do not edit files under node_modules; use the package manager for dependencies.",
        ]
        .join("\n");

        assert_eq!(task, expected);
    }

    #[test]
    fn build_agent_task_includes_declared_deps_and_context_deps() {
        let fm = frontmatter("m", vec!["dep-a", "dep-b"]);
        let a = adapter();
        let deps = vec![
            DepSummary { module: "dep-a".to_string(), summary: "does a".to_string() },
            DepSummary { module: "dep-b".to_string(), summary: "does b".to_string() },
        ];
        let task = build_agent_task(&a, &fm, "Body.", &deps, None);

        assert!(task.contains("Declared dependencies: dep-a, dep-b"));
        assert!(task.contains("Other modules in this project (for context, do not reimplement them):"));
        assert!(task.contains("- dep-a: does a"));
        assert!(task.contains("- dep-b: does b"));
    }

    #[test]
    fn build_agent_task_appends_failure_block() {
        let fm = frontmatter("m", Vec::new());
        let a = adapter();
        let task = build_agent_task(&a, &fm, "Body.", &[], Some("  boom\nstack trace  "));

        assert!(task.ends_with(
            "\n\nA previous attempt FAILED its tests. Read the current files, fix the code and/or tests,\nand make the suite pass. Test output from the failed attempt:\n```\nboom\nstack trace\n```"
        ));
    }

    #[test]
    fn build_agent_task_truncates_long_failure_to_6000_chars() {
        let fm = frontmatter("m", Vec::new());
        let a = adapter();
        let long_failure = "x".repeat(7000);
        let task = build_agent_task(&a, &fm, "Body.", &[], Some(&long_failure));
        let expected_tail = "x".repeat(6000);
        assert!(task.contains(&format!("```\n{expected_tail}\n```")));
        assert!(!task.contains(&"x".repeat(6001)));
    }

    #[test]
    fn build_incremental_task_minimal_shape() {
        let fm = frontmatter("m", Vec::new());
        let a = adapter();
        let input = IncrementalTaskInput {
            module: "m".to_string(),
            diff: "-old\n+new".to_string(),
            intersecting_entries: Vec::new(),
            owned_files: Vec::new(),
        };
        let task = build_incremental_task(&a, &fm, "New body.", &input, None);

        assert!(task.starts_with(
            "You are a coding agent making an INCREMENTAL update to the existing module \"m\""
        ));
        assert!(task.contains("```diff\n-old\n+new\n```"));
        assert!(task.contains("Full current prompt body (the target behavior after the change):"));
        assert!(!task.contains("Prefer editing exactly these regions:"));
        assert!(!task.contains("Files owned by this module"));
    }

    #[test]
    fn build_incremental_task_includes_intersecting_entries_and_owned_files() {
        let fm = frontmatter("m", Vec::new());
        let a = adapter();
        let input = IncrementalTaskInput {
            module: "m".to_string(),
            diff: "diff".to_string(),
            intersecting_entries: vec![
                AttributionEntry {
                    prompt_lines: LineRange::new(1, 2),
                    file: "src/lib.rs".to_string(),
                    lines: LineRange::new(10, 20),
                    note: "trims whitespace".to_string(),
                },
                AttributionEntry {
                    prompt_lines: LineRange::new(3, 3),
                    file: "src/other.rs".to_string(),
                    lines: LineRange::new(1, 1),
                    note: String::new(),
                },
            ],
            owned_files: vec!["src/lib.rs".to_string(), "src/other.rs".to_string()],
        };
        let task = build_incremental_task(&a, &fm, "Body.", &input, None);

        assert!(task.contains("The changed prompt lines are currently implemented by these owned code regions."));
        assert!(task.contains("Prefer editing exactly these regions:"));
        assert!(task.contains("- src/lib.rs lines 10-20 — trims whitespace"));
        assert!(task.contains("- src/other.rs lines 1-1"));
        assert!(!task.contains("- src/other.rs lines 1-1 —"));
        assert!(task.contains("Files owned by this module (edit only what the change requires):"));
        assert!(task.contains("- src/lib.rs"));
    }

    #[test]
    fn build_incremental_task_appends_failure_block() {
        let fm = frontmatter("m", Vec::new());
        let a = adapter();
        let input = IncrementalTaskInput {
            module: "m".to_string(),
            diff: "diff".to_string(),
            intersecting_entries: Vec::new(),
            owned_files: Vec::new(),
        };
        let task = build_incremental_task(&a, &fm, "Body.", &input, Some("failure output"));
        assert!(task.contains("A previous attempt FAILED its tests."));
        assert!(task.contains("failure output"));
    }

    #[test]
    fn build_reconcile_task_shape() {
        let files = vec![ReconcileFile {
            file: "src/lib.rs".to_string(),
            diff: "-old\n+new".to_string(),
        }];
        let task = build_reconcile_task("m", "m.prompt.md", "Body.", &files);

        assert!(task.contains(
            "You are reconciling hand edits back into the prompt (the durable source of truth) for the module \"m\"."
        ));
        assert!(task.contains("Prompt file to amend: m.prompt.md"));
        assert!(task.contains("=== FILE: src/lib.rs ==="));
        assert!(task.contains("```diff\n-old\n+new\n```"));
        assert!(task.contains("Do not edit, create, or delete any file under .napl/src"));
    }

    #[test]
    fn build_change_required_retry_appends_escalation() {
        let base = "base task text";
        let retry = build_change_required_retry(base);
        assert!(retry.starts_with("base task text\n\nCRITICAL: A previous attempt made NO source changes at all"));
        assert!(retry.contains("Do not finish silently without doing one of these."));
    }

    #[test]
    fn build_ir_derivation_user_shape() {
        let out = build_ir_derivation_user("m", "  Body.  \n", "file contents\n\ntrailing");
        assert_eq!(
            out,
            "Module name: m\n\nPrompt (the contract, in prose):\n\"\"\"\nBody.\n\"\"\"\n\nImplementing source files:\nfile contents\n\ntrailing"
        );
    }

    #[test]
    fn build_attribution_user_shape() {
        let out = build_attribution_user("m", "1: body", "1: file");
        assert_eq!(
            out,
            "Module: m\n\nPrompt body (1-based line numbers):\n1: body\n\nImplementing source files (1-based line numbers):\n1: file"
        );
    }

    #[test]
    fn build_attribution_repair_truncates_and_trims_previous_output() {
        let previous = format!("  {}  ", "y".repeat(4010));
        let out = build_attribution_repair(&previous, "bad yaml");
        assert!(out.contains(&"y".repeat(4000)));
        assert!(!out.contains(&"y".repeat(4001)));
        assert!(out.starts_with("\nYour PREVIOUS response was REJECTED as invalid and MUST be corrected. Return ONLY a single"));
        assert!(out.contains("fenced ```yaml code block containing the list"));
        assert!(out.contains("The validation error was:\nbad yaml"));
    }

    #[test]
    fn build_ml_derivation_user_uses_placeholder_for_empty_output() {
        let out = build_ml_derivation_user("m", "1: body", "NO CHANGES", "   ");
        assert!(out.contains("The coding agent's final message:\n\"\"\"\n(no output captured)\n\"\"\""));
    }

    #[test]
    fn build_ml_derivation_user_truncates_agent_output_to_4000_chars() {
        let long_output = "z".repeat(4500);
        let out = build_ml_derivation_user("m", "1: body", "NO CHANGES", &long_output);
        let expected_tail = "z".repeat(4000);
        assert!(out.contains(&format!("\"\"\"\n{expected_tail}\n\"\"\"")));
    }

    #[test]
    fn system_prompt_routing_markers() {
